# Spec 01: Types and Schema Validation

**Files:** `types.ts`, `schema-validator.ts`
**Dependencies:** none (leaf modules)
**npm deps:** `ajv`, `yaml`

## types.ts

All shared interfaces for the workflow extension. No logic, no imports from other extension files.

```typescript
// ── Workflow Spec (parsed from YAML) ──

export interface WorkflowSpec {
  name: string;
  description: string;
  version?: string;
  input?: Record<string, unknown>;       // JSON Schema object
  output?: Record<string, unknown>;      // JSON Schema object
  triggerTurn?: boolean;                  // default: true
  steps: Record<string, StepSpec>;       // ordered (YAML preserves insertion order)
  // Set by discovery, not by YAML:
  source: "user" | "project";
  filePath: string;
}

export interface StepSpec {
  agent: string;                         // agent name (required in phase 1)
  model?: string;                        // model override
  input?: Record<string, unknown>;       // values may contain ${{ }} expressions
  output?: StepOutputSpec;
  // Phase 2+:
  when?: string;
  timeout?: { seconds: number };
  loop?: unknown;
  gate?: unknown;
  transform?: unknown;
  workflow?: string;
}

export interface StepOutputSpec {
  format?: "json" | "text";              // default: "text"
  schema?: string;                       // path to JSON Schema file, relative to workflow spec
}

// ── Agent Spec (loaded from .md frontmatter or .agent.yaml) ──

export interface AgentSpec {
  name: string;
  description?: string;
  systemPrompt?: string;
  model?: string;
  thinking?: string;
  tools?: string[];
  extensions?: string[];
  skills?: string[];
  output?: string;                       // output file path
}

// ── Execution State ──

export interface ExecutionState {
  input: unknown;
  steps: Record<string, StepResult>;
  status: "running" | "completed" | "failed";
}

export interface StepResult {
  step: string;
  agent: string;
  status: "completed" | "failed" | "skipped";
  output?: unknown;                      // parsed structured output (if schema-bound)
  textOutput?: string;                   // raw text from last assistant message
  sessionLog?: string;                   // path to session log file
  usage: StepUsage;
  durationMs: number;
  error?: string;                        // error message if failed
}

export interface StepUsage {
  input: number;
  output: number;
  cacheRead: number;
  cacheWrite: number;
  cost: number;
  turns: number;
}

// ── Workflow Result (returned to caller) ──

export interface WorkflowResult {
  workflow: string;
  runId: string;
  status: "completed" | "failed";
  steps: Record<string, StepResult>;
  output?: unknown;                      // final workflow output (last step's output, or explicit)
  totalUsage: StepUsage;
  totalDurationMs: number;
  runDir: string;                        // absolute path to .pi/workflow-runs/<run-id>/
}

// ── Expression Scope (what ${{ }} expressions resolve against) ──

export interface ExpressionScope {
  input: unknown;
  steps: Record<string, StepResult>;
}
```

### Constraints

- All fields that come from YAML use `Record<string, unknown>` for JSON Schema objects (not a specific JSON Schema type — AJV handles validation).
- `StepSpec.agent` is required in phase 1. In later phases, exactly one of `agent`, `workflow`, `transform`, `gate` must be set.
- `source` and `filePath` are set by the discovery module, not present in the YAML file itself.
- `steps` is `Record<string, StepSpec>` — JavaScript/YAML preserves insertion order for string keys, so iteration order = declaration order = execution order.

## schema-validator.ts

AJV wrapper for validating workflow inputs, step outputs, and workflow spec structure.

### Exports

```typescript
import Ajv from "ajv";

const ajv = new Ajv({ allErrors: true, strict: false });

/**
 * Validate data against a JSON Schema object.
 * Throws ValidationError with formatted error messages on failure.
 * Returns the validated data on success (pass-through).
 */
export function validate(schema: Record<string, unknown>, data: unknown, label: string): unknown;

/**
 * Load a JSON Schema from a file path and validate data against it.
 * Throws if the schema file doesn't exist or is invalid JSON.
 * Throws ValidationError on validation failure.
 */
export function validateFromFile(schemaPath: string, data: unknown, label: string): unknown;

/**
 * Error class for validation failures.
 * Contains the original AJV errors and a formatted message.
 */
export class ValidationError extends Error {
  constructor(
    public readonly label: string,
    public readonly errors: Ajv.ErrorObject[],
  );
}
```

### Behavior

- `validate()` compiles the schema (AJV caches compiled schemas), runs validation, throws `ValidationError` on failure.
- `ValidationError.message` format: `"Validation failed for <label>: <error1>; <error2>; ..."`. Each error includes the JSON path and message, e.g. `"/description: must be string"`.
- `validateFromFile()` reads the file with `fs.readFileSync`, parses with `JSON.parse`, delegates to `validate()`. If the file doesn't exist: `throw new Error("Schema file not found: <path>")`. If JSON is invalid: `throw new Error("Invalid JSON in schema file: <path>: <parse error>")`.
- `label` is a human-readable identifier for error messages, e.g. `"workflow input for 'bugfix'"` or `"step output for 'diagnose'"`.
- AJV is configured with `allErrors: true` (report all errors, not just the first) and `strict: false` (accept JSON Schema draft-07 and later without warnings about unknown keywords).

### Error examples

```
Validation failed for workflow input for 'bugfix': /description: must be string; /maxAttempts: must be integer
Validation failed for step output for 'diagnose': /rootCause: is required; /reproCommand: is required
Schema file not found: ./schemas/bugfix-diagnosis.schema.json
```

## Tests

File: `types.test.ts` — no tests needed (pure type definitions, no runtime logic).

File: `schema-validator.test.ts`:

```typescript
import { describe, it } from "node:test";
import assert from "node:assert";
import { validate, validateFromFile, ValidationError } from "./schema-validator.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

describe("validate", () => {
  it("passes valid data through", () => {
    const schema = {
      type: "object",
      required: ["name"],
      properties: { name: { type: "string" } },
    };
    const data = { name: "test" };
    const result = validate(schema, data, "test");
    assert.deepStrictEqual(result, data);
  });

  it("throws ValidationError on invalid data", () => {
    const schema = {
      type: "object",
      required: ["name"],
      properties: { name: { type: "string" } },
    };
    assert.throws(
      () => validate(schema, { name: 123 }, "test input"),
      (err: unknown) => {
        assert.ok(err instanceof ValidationError);
        assert.ok(err.message.includes("test input"));
        assert.ok(err.message.includes("/name"));
        return true;
      },
    );
  });

  it("throws ValidationError for missing required fields", () => {
    const schema = {
      type: "object",
      required: ["name", "age"],
      properties: {
        name: { type: "string" },
        age: { type: "integer" },
      },
    };
    assert.throws(
      () => validate(schema, {}, "person"),
      (err: unknown) => {
        assert.ok(err instanceof ValidationError);
        assert.ok(err.errors.length >= 2); // allErrors: true
        return true;
      },
    );
  });

  it("accepts data with no schema constraints (empty schema)", () => {
    const result = validate({}, { anything: "goes" }, "open");
    assert.deepStrictEqual(result, { anything: "goes" });
  });
});

describe("validateFromFile", () => {
  it("validates against a schema file", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-test-"));
    const schemaPath = path.join(tmpDir, "test.schema.json");
    fs.writeFileSync(schemaPath, JSON.stringify({
      type: "object",
      required: ["id"],
      properties: { id: { type: "string" } },
    }));

    const result = validateFromFile(schemaPath, { id: "abc" }, "test");
    assert.deepStrictEqual(result, { id: "abc" });

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("throws on missing schema file", () => {
    assert.throws(
      () => validateFromFile("/nonexistent/schema.json", {}, "test"),
      (err: unknown) => err instanceof Error && err.message.includes("Schema file not found"),
    );
  });

  it("throws on invalid JSON in schema file", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-test-"));
    const schemaPath = path.join(tmpDir, "bad.schema.json");
    fs.writeFileSync(schemaPath, "not json{{{");

    assert.throws(
      () => validateFromFile(schemaPath, {}, "test"),
      (err: unknown) => err instanceof Error && err.message.includes("Invalid JSON"),
    );

    fs.rmSync(tmpDir, { recursive: true });
  });
});
```

# Spec 02: Expression Evaluator

**File:** `expression.ts`
**Dependencies:** `types.ts`

## Purpose

Resolve `${{ }}` expressions in workflow step inputs. Expressions are simple property access paths into a scope object containing `input` and `steps`.

## Exports

```typescript
import type { ExpressionScope } from "./types.ts";

/**
 * Resolve all ${{ }} expressions in a value.
 *
 * - If `value` is a string containing `${{ expr }}`, resolve the expression.
 * - If `value` is a string that IS entirely `${{ expr }}`, return the resolved value
 *   (preserving its type — object, array, number, etc.).
 * - If `value` is a string with `${{ expr }}` embedded in other text,
 *   stringify the resolved value and interpolate.
 * - If `value` is an object, recursively resolve all values.
 * - If `value` is an array, recursively resolve all elements.
 * - If `value` is anything else (number, boolean, null), return as-is.
 *
 * Throws ExpressionError if a property path doesn't resolve.
 */
export function resolveExpressions(value: unknown, scope: ExpressionScope): unknown;

/**
 * Resolve a single expression string (without the ${{ }} delimiters).
 * E.g. "steps.diagnose.output.rootCause" → walks scope.steps.diagnose.output.rootCause
 *
 * Throws ExpressionError if any segment of the path is undefined.
 */
export function resolveExpression(expr: string, scope: ExpressionScope): unknown;

/**
 * Error class for expression resolution failures.
 */
export class ExpressionError extends Error {
  constructor(
    public readonly expression: string,
    public readonly reason: string,
  );
}
```

## Behavior

### Expression syntax

The pattern is `${{ <path> }}`. Whitespace inside the braces is trimmed.

- `${{ input.description }}` → `scope.input.description`
- `${{ steps.diagnose.output }}` → `scope.steps.diagnose.output` (whole object)
- `${{ steps.diagnose.output.fixLocation.file }}` → nested property access
- `${{ steps.diagnose.status }}` → `"completed"` (string)
- `${{ steps.diagnose.usage.cost }}` → `0.03` (number)

### Resolution rules

1. **Whole-value expression**: if the entire string is `${{ expr }}` (no surrounding text), return the resolved value with its original type. This allows passing objects and arrays between steps:
   ```yaml
   input:
     diagnosis: ${{ steps.diagnose.output }}   # passes the full object, not a string
   ```

2. **Embedded expression**: if `${{ expr }}` appears within other text, stringify the resolved value with `JSON.stringify()` for objects/arrays, `String()` for primitives:
   ```yaml
   input:
     message: "Bug in ${{ steps.diagnose.output.fixLocation.file }} at line ${{ steps.diagnose.output.fixLocation.line }}"
   ```

3. **Multiple expressions** in one string: all are resolved left-to-right:
   ```yaml
   input:
     summary: "${{ steps.diagnose.output.summary }} (risk: ${{ steps.diagnose.output.riskAssessment }})"
   ```

4. **No expression**: strings without `${{ }}` are returned as-is.

5. **Recursive resolution**: objects and arrays are walked recursively. Only string values are checked for expressions.

### Path resolution

`resolveExpression("steps.diagnose.output.rootCause", scope)`:

1. Split on `.` → `["steps", "diagnose", "output", "rootCause"]`
2. Start at `scope`
3. Walk: `scope["steps"]` → `scope.steps["diagnose"]` → `.output` → `.rootCause`
4. If any segment resolves to `undefined` or `null`, throw `ExpressionError`

### Error messages

```
Expression error in '${{ steps.diagnose.output.rootCause }}': property 'output' is undefined on steps.diagnose (step 'diagnose' status: failed)
Expression error in '${{ steps.verify.output }}': step 'verify' has not been executed yet
Expression error in '${{ input.nonexistent }}': property 'nonexistent' is undefined on input
```

The error should be as diagnostic as possible — include the full expression, which segment failed, and context about the step's status if the path starts with `steps.`.

### Regex

```typescript
const EXPR_PATTERN = /\$\{\{\s*(.*?)\s*\}\}/g;
```

## Tests

File: `expression.test.ts`:

```typescript
import { describe, it } from "node:test";
import assert from "node:assert";
import { resolveExpressions, resolveExpression, ExpressionError } from "./expression.ts";
import type { ExpressionScope } from "./types.ts";

const scope: ExpressionScope = {
  input: {
    description: "null pointer in login",
    maxAttempts: 3,
    tags: ["auth", "critical"],
  },
  steps: {
    diagnose: {
      step: "diagnose",
      agent: "diagnostician",
      status: "completed",
      output: {
        summary: "NPE in UserService.login()",
        rootCause: "session param is null",
        fixLocation: { file: "src/auth/user-service.ts", line: 47 },
        reproCommand: "npm test -- --grep login",
      },
      textOutput: "Found the bug...",
      usage: { input: 1000, output: 500, cacheRead: 0, cacheWrite: 0, cost: 0.03, turns: 2 },
      durationMs: 42000,
    },
  },
};

describe("resolveExpression", () => {
  it("resolves input properties", () => {
    assert.strictEqual(resolveExpression("input.description", scope), "null pointer in login");
  });

  it("resolves input number", () => {
    assert.strictEqual(resolveExpression("input.maxAttempts", scope), 3);
  });

  it("resolves step output object", () => {
    const result = resolveExpression("steps.diagnose.output", scope);
    assert.strictEqual(typeof result, "object");
    assert.strictEqual((result as any).summary, "NPE in UserService.login()");
  });

  it("resolves nested step output", () => {
    assert.strictEqual(
      resolveExpression("steps.diagnose.output.fixLocation.file", scope),
      "src/auth/user-service.ts",
    );
  });

  it("resolves step metadata", () => {
    assert.strictEqual(resolveExpression("steps.diagnose.status", scope), "completed");
    assert.strictEqual(resolveExpression("steps.diagnose.usage.cost", scope), 0.03);
  });

  it("throws on undefined property", () => {
    assert.throws(
      () => resolveExpression("input.nonexistent", scope),
      (err: unknown) => err instanceof ExpressionError,
    );
  });

  it("throws on unexecuted step", () => {
    assert.throws(
      () => resolveExpression("steps.fix.output", scope),
      (err: unknown) => err instanceof ExpressionError && err.message.includes("fix"),
    );
  });
});

describe("resolveExpressions", () => {
  it("resolves whole-value expression preserving type", () => {
    const result = resolveExpressions("${{ steps.diagnose.output }}", scope);
    assert.strictEqual(typeof result, "object");
    assert.strictEqual((result as any).summary, "NPE in UserService.login()");
  });

  it("resolves whole-value expression preserving number", () => {
    const result = resolveExpressions("${{ input.maxAttempts }}", scope);
    assert.strictEqual(result, 3);
  });

  it("resolves whole-value expression preserving array", () => {
    const result = resolveExpressions("${{ input.tags }}", scope);
    assert.ok(Array.isArray(result));
    assert.deepStrictEqual(result, ["auth", "critical"]);
  });

  it("resolves embedded expression as string interpolation", () => {
    const result = resolveExpressions(
      "Bug in ${{ steps.diagnose.output.fixLocation.file }} at line ${{ steps.diagnose.output.fixLocation.line }}",
      scope,
    );
    assert.strictEqual(result, "Bug in src/auth/user-service.ts at line 47");
  });

  it("resolves object values recursively", () => {
    const input = {
      description: "${{ input.description }}",
      diagnosis: "${{ steps.diagnose.output }}",
      nested: {
        file: "${{ steps.diagnose.output.fixLocation.file }}",
        plain: "no expression here",
      },
    };
    const result = resolveExpressions(input, scope) as any;
    assert.strictEqual(result.description, "null pointer in login");
    assert.strictEqual(typeof result.diagnosis, "object");
    assert.strictEqual(result.nested.file, "src/auth/user-service.ts");
    assert.strictEqual(result.nested.plain, "no expression here");
  });

  it("resolves array elements", () => {
    const input = ["${{ input.description }}", "${{ input.maxAttempts }}"];
    const result = resolveExpressions(input, scope) as unknown[];
    assert.strictEqual(result[0], "null pointer in login");
    assert.strictEqual(result[1], 3);
  });

  it("passes through non-string primitives", () => {
    assert.strictEqual(resolveExpressions(42, scope), 42);
    assert.strictEqual(resolveExpressions(true, scope), true);
    assert.strictEqual(resolveExpressions(null, scope), null);
  });

  it("passes through strings with no expressions", () => {
    assert.strictEqual(resolveExpressions("plain string", scope), "plain string");
  });

  it("handles whitespace in expressions", () => {
    assert.strictEqual(
      resolveExpressions("${{   input.description   }}", scope),
      "null pointer in login",
    );
  });

  it("stringifies objects in embedded expressions", () => {
    const result = resolveExpressions(
      "Location: ${{ steps.diagnose.output.fixLocation }}",
      scope,
    );
    assert.ok(typeof result === "string");
    assert.ok((result as string).includes("src/auth/user-service.ts"));
  });
});
```

# Spec 03: Workflow Spec Parsing and Discovery

**Files:** `workflow-spec.ts`, `workflow-discovery.ts`
**Dependencies:** `types.ts`, `schema-validator.ts`
**npm deps:** `yaml`

## workflow-spec.ts

Parse and validate `.workflow.yaml` files into `WorkflowSpec` objects.

### Exports

```typescript
import type { WorkflowSpec } from "./types.ts";

/**
 * Parse a YAML string into a WorkflowSpec.
 * Validates structure (required fields, types).
 * Does NOT validate JSON Schemas or resolve agent references — that happens at execution time.
 *
 * @param content - raw YAML string
 * @param filePath - absolute path to the file (stored on the spec, used in error messages)
 * @param source - "user" or "project"
 * @throws WorkflowSpecError on invalid structure
 */
export function parseWorkflowSpec(content: string, filePath: string, source: "user" | "project"): WorkflowSpec;

/**
 * Error class for spec parsing failures.
 */
export class WorkflowSpecError extends Error {
  constructor(
    public readonly filePath: string,
    public readonly reason: string,
  );
}
```

### Behavior

`parseWorkflowSpec()`:

1. Parse YAML with the `yaml` package. If YAML is invalid, throw `WorkflowSpecError`.
2. Validate required fields:
   - `name`: string, required. Error if missing or not a string.
   - `steps`: object with at least one key, required. Error if missing, not an object, or empty.
3. Validate each step in `steps`:
   - `agent`: string, required (in phase 1). Error if missing.
   - `input`: if present, must be an object. Error if not.
   - `output`: if present, must be an object. If `output.schema` is present, must be a string.
   - `model`: if present, must be a string.
4. Optional fields with defaults:
   - `description`: string, defaults to `""`.
   - `version`: string, no default.
   - `input`: JSON Schema object, no default (no input validation if absent).
   - `output`: JSON Schema object, no default.
   - `triggerTurn`: boolean, defaults to `true`.
5. Set `source` and `filePath` from arguments.
6. Return the `WorkflowSpec`.

### Valid workflow YAML

```yaml
name: bugfix
description: Diagnose and fix a bug
version: "1"
triggerTurn: true

input:
  type: object
  required: [description]
  properties:
    description:
      type: string

steps:
  diagnose:
    agent: bug-diagnostician
    input:
      description: ${{ input.description }}
    output:
      format: json
      schema: ./schemas/diagnosis.schema.json

  fix:
    agent: bug-fixer
    model: claude-sonnet-4-6
    input:
      diagnosis: ${{ steps.diagnose.output }}
```

### Error messages

```
Invalid workflow spec (./workflows/bugfix.workflow.yaml): 'name' is required
Invalid workflow spec (./workflows/bugfix.workflow.yaml): 'steps' must be a non-empty object
Invalid workflow spec (./workflows/bugfix.workflow.yaml): step 'diagnose' is missing 'agent'
Invalid workflow spec (./workflows/bugfix.workflow.yaml): step 'fix' input must be an object
Invalid workflow spec (./workflows/bugfix.workflow.yaml): invalid YAML: <yaml parse error>
```

## workflow-discovery.ts

Scan directories for `.workflow.yaml` files, parse them, return a list of specs.

### Exports

```typescript
import type { WorkflowSpec } from "./types.ts";

/**
 * Discover all workflow specs from project and user directories.
 *
 * Scans:
 *   1. .pi/workflows/             (project-level, source: "project")
 *   2. ~/.pi/agent/workflows/     (user-level, source: "user")
 *
 * Project-level specs take precedence over user-level specs with the same name.
 *
 * @param cwd - current working directory (project root)
 * @returns Array of parsed WorkflowSpec objects. Specs that fail parsing are
 *          skipped with a warning (logged to stderr), not thrown.
 */
export function discoverWorkflows(cwd: string): WorkflowSpec[];

/**
 * Find a workflow by name from discovered workflows.
 * Returns undefined if not found.
 */
export function findWorkflow(name: string, cwd: string): WorkflowSpec | undefined;
```

### Behavior

`discoverWorkflows()`:

1. Build directory list:
   - Project: `path.join(cwd, ".pi", "workflows")`
   - User: `path.join(os.homedir(), ".pi", "agent", "workflows")`
2. For each directory (if it exists), find all files matching `*.workflow.yaml` (non-recursive).
3. Parse each file with `parseWorkflowSpec()`.
4. If parsing fails, log to stderr: `[pi-workflows] Warning: skipping <path>: <error>` and continue.
5. Deduplicate by name: if a project-level spec has the same name as a user-level spec, the project-level spec wins.
6. Return the list sorted by name.

`findWorkflow()`: calls `discoverWorkflows()`, returns the first spec matching the name.

### Directory structure

```
.pi/workflows/
  bugfix.workflow.yaml        → source: "project"
  review.workflow.yaml        → source: "project"

~/.pi/agent/workflows/
  bugfix.workflow.yaml        → source: "user" (shadowed by project)
  deploy.workflow.yaml        → source: "user"
```

Result: `[bugfix (project), deploy (user), review (project)]`

## Tests

File: `workflow-spec.test.ts`:

```typescript
import { describe, it } from "node:test";
import assert from "node:assert";
import { parseWorkflowSpec, WorkflowSpecError } from "./workflow-spec.ts";

describe("parseWorkflowSpec", () => {
  it("parses a minimal valid spec", () => {
    const yaml = `
name: test
steps:
  step1:
    agent: my-agent
`;
    const spec = parseWorkflowSpec(yaml, "/test.workflow.yaml", "project");
    assert.strictEqual(spec.name, "test");
    assert.strictEqual(spec.steps.step1.agent, "my-agent");
    assert.strictEqual(spec.source, "project");
    assert.strictEqual(spec.filePath, "/test.workflow.yaml");
    assert.strictEqual(spec.triggerTurn, true); // default
  });

  it("parses a full spec", () => {
    const yaml = `
name: bugfix
description: Fix a bug
version: "1"
triggerTurn: false
input:
  type: object
  required: [description]
  properties:
    description:
      type: string
steps:
  diagnose:
    agent: diagnostician
    input:
      description: \${{ input.description }}
    output:
      format: json
      schema: ./schemas/diagnosis.schema.json
  fix:
    agent: fixer
    model: claude-sonnet-4-6
    input:
      diagnosis: \${{ steps.diagnose.output }}
`;
    const spec = parseWorkflowSpec(yaml, "/bugfix.workflow.yaml", "user");
    assert.strictEqual(spec.name, "bugfix");
    assert.strictEqual(spec.description, "Fix a bug");
    assert.strictEqual(spec.triggerTurn, false);
    assert.strictEqual(spec.steps.diagnose.agent, "diagnostician");
    assert.strictEqual(spec.steps.diagnose.output?.schema, "./schemas/diagnosis.schema.json");
    assert.strictEqual(spec.steps.fix.model, "claude-sonnet-4-6");
  });

  it("throws on missing name", () => {
    assert.throws(
      () => parseWorkflowSpec("steps:\n  s:\n    agent: a", "/t.yaml", "project"),
      (err: unknown) => err instanceof WorkflowSpecError && err.message.includes("name"),
    );
  });

  it("throws on missing steps", () => {
    assert.throws(
      () => parseWorkflowSpec("name: test", "/t.yaml", "project"),
      (err: unknown) => err instanceof WorkflowSpecError && err.message.includes("steps"),
    );
  });

  it("throws on empty steps", () => {
    assert.throws(
      () => parseWorkflowSpec("name: test\nsteps: {}", "/t.yaml", "project"),
      (err: unknown) => err instanceof WorkflowSpecError && err.message.includes("non-empty"),
    );
  });

  it("throws on step missing agent", () => {
    assert.throws(
      () => parseWorkflowSpec("name: test\nsteps:\n  s:\n    model: foo", "/t.yaml", "project"),
      (err: unknown) => err instanceof WorkflowSpecError && err.message.includes("agent"),
    );
  });

  it("throws on invalid YAML", () => {
    assert.throws(
      () => parseWorkflowSpec("name: [[[invalid", "/t.yaml", "project"),
      (err: unknown) => err instanceof WorkflowSpecError,
    );
  });

  it("preserves step order", () => {
    const yaml = `
name: test
steps:
  third:
    agent: c
  first:
    agent: a
  second:
    agent: b
`;
