### Notes

- `type: "module"` — ESM, matches pi's module system.
- `pi.extensions` points to `index.ts` — pi loads this as the extension entry point. Pi supports `.ts` files directly via `--experimental-strip-types`.
- `peerDependencies` — pi bundles these; the extension should not bundle them.
- `ajv` and `yaml` are runtime dependencies owned by this package.
- No build step. Pi loads `.ts` files directly.

## index.ts

Extension factory function. Registers the `workflow` tool, `/workflow` commands, and wires everything together.

### Structure

```typescript
import type { ExtensionFactory, ExtensionAPI, ExtensionContext, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { discoverWorkflows, findWorkflow } from "./workflow-discovery.ts";
import { executeWorkflow } from "./workflow-executor.ts";
import { parseAgentFrontmatter } from "./workflow-spec.ts";
import type { AgentSpec } from "./types.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

const extension: ExtensionFactory = (pi: ExtensionAPI) => {
  // ── Tool: workflow ──────────────────────────────────────────────────────

  pi.registerTool({
    name: "workflow",
    label: "Workflow",
    description: "Run a named workflow with typed input. Discovers workflows from .pi/workflows/ and ~/.pi/agent/workflows/.",
    promptSnippet: "Run a multi-step workflow with typed data flow between agents",
    parameters: Type.Object({
      workflow: Type.String({ description: "Name of the workflow to run" }),
      input: Type.Optional(Type.Unknown({ description: "Input data for the workflow (validated against workflow's input schema)" })),
    }),

    async execute(toolCallId, params, signal, onUpdate, ctx) {
      const spec = findWorkflow(params.workflow, ctx.cwd);
      if (!spec) {
        return {
          content: [{ type: "text", text: `Workflow '${params.workflow}' not found. Available workflows: ${listWorkflowNames(ctx.cwd)}` }],
          details: undefined,
        };
      }

      try {
        const result = await executeWorkflow(spec, params.input ?? {}, {
          ctx,
          pi,
          signal,
          loadAgent: createAgentLoader(ctx.cwd),
        });

        return {
          content: [{ type: "text", text: formatToolResult(result) }],
          details: result,
        };
      } catch (err) {
        return {
          content: [{ type: "text", text: `Workflow '${params.workflow}' failed: ${err instanceof Error ? err.message : String(err)}` }],
          details: undefined,
        };
      }
    },
  });

  // ── Command: /workflow ──────────────────────────────────────────────────

  pi.registerCommand("workflow", {
    description: "List and run workflows",
    getArgumentCompletions: (prefix) => {
      const subcommands = ["run", "list", "status"];
      return subcommands
        .filter((s) => s.startsWith(prefix))
        .map((s) => ({ value: s, label: s }));
    },

    async handler(args: string, ctx: ExtensionCommandContext) {
      const parts = args.trim().split(/\s+/);
      const subcommand = parts[0] || "list";

      if (subcommand === "list") {
        await handleList(ctx);
      } else if (subcommand === "run") {
        await handleRun(parts.slice(1), ctx, pi);
      } else if (subcommand === "status") {
        ctx.ui.notify("No workflow currently running.", "info");
      } else {
        ctx.ui.notify(`Unknown subcommand: ${subcommand}. Use: list, run, status`, "warning");
      }
    },
  });
};

export default extension;
```

### Command handlers

```typescript
async function handleList(ctx: ExtensionContext) {
  const workflows = discoverWorkflows(ctx.cwd);
  if (workflows.length === 0) {
    ctx.ui.notify("No workflows found in .pi/workflows/ or ~/.pi/agent/workflows/", "info");
    return;
  }

  const lines = workflows.map((w) => {
    const source = w.source === "project" ? "[project]" : "[user]";
    const desc = w.description ? ` — ${w.description}` : "";
    return `  ${w.name} ${source}${desc}`;
  });
  ctx.ui.notify(`Available workflows:\n${lines.join("\n")}`, "info");
}

async function handleRun(args: string[], ctx: ExtensionCommandContext, pi: ExtensionAPI) {
  const name = args[0];
  if (!name) {
    ctx.ui.notify("Usage: /workflow run <name> [--input '<json>']", "warning");
    return;
  }

  const spec = findWorkflow(name, ctx.cwd);
  if (!spec) {
    ctx.ui.notify(`Workflow '${name}' not found.`, "warning");
    return;
  }

  // Parse --input if provided
  let input: unknown = {};
  const inputIdx = args.indexOf("--input");
  if (inputIdx !== -1 && args[inputIdx + 1]) {
    try {
      input = JSON.parse(args[inputIdx + 1]);
    } catch {
      ctx.ui.notify("Invalid JSON for --input", "warning");
      return;
    }
  }

  try {
    await executeWorkflow(spec, input, {
      ctx,
      pi,
      loadAgent: createAgentLoader(ctx.cwd),
    });
    // Result is injected into conversation by executeWorkflow via sendMessage
  } catch (err) {
    ctx.ui.notify(
      `Workflow '${name}' failed: ${err instanceof Error ? err.message : String(err)}`,
      "error",
    );
  }
}
```

### Agent loader

```typescript
function createAgentLoader(cwd: string): (name: string) => AgentSpec {
  return (name: string): AgentSpec => {
    const searchPaths = [
      path.join(cwd, ".pi", "agents", `${name}.md`),
      path.join(os.homedir(), ".pi", "agent", "agents", `${name}.md`),
    ];

    for (const agentPath of searchPaths) {
      if (fs.existsSync(agentPath)) {
        return parseAgentFrontmatter(agentPath);
      }
    }

    return { name };
  };
}

/**
 * Parse YAML frontmatter from a .md agent file.
 * Frontmatter is between --- markers at the start of the file.
 * Content after frontmatter is the system prompt.
 */
function parseAgentFrontmatter(filePath: string): AgentSpec {
  const content = fs.readFileSync(filePath, "utf-8");
  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);

  if (!match) {
    return { name: path.basename(filePath, ".md") };
  }

  const yaml = await import("yaml");
  const frontmatter = yaml.parse(match[1]);
  const systemPrompt = match[2].trim();

  return {
    name: frontmatter.name || path.basename(filePath, ".md"),
    description: frontmatter.description,
    model: frontmatter.model,
    thinking: frontmatter.thinking,
    tools: frontmatter.tools,
    extensions: frontmatter.extensions,
    skills: frontmatter.skills,
    output: frontmatter.output,
    systemPrompt: systemPrompt || undefined,
  };
}
```

**Note on inline import:** The `parseAgentFrontmatter` function shown above uses `await import("yaml")` for illustration. Per the project rules (no inline imports), the actual implementation must use a top-level `import { parse } from "yaml"` and call it directly. The spec shows the logic; the implementer must restructure to use top-level imports.

### Helper functions

```typescript
function listWorkflowNames(cwd: string): string {
  const workflows = discoverWorkflows(cwd);
  if (workflows.length === 0) return "(none)";
  return workflows.map((w) => w.name).join(", ");
}

function formatToolResult(result: WorkflowResult): string {
  // Concise version for tool result (the full format is in sendMessage)
  const status = result.status === "completed" ? "completed" : "failed";
  const stepSummary = Object.entries(result.steps)
    .map(([name, s]) => `${s.status === "completed" ? "✓" : "✗"} ${name}`)
    .join(", ");
  return `Workflow '${result.workflow}' ${status}: ${stepSummary}. Run dir: ${result.runDir}`;
}
```

## Demo Workflow

A minimal 2-step workflow that proves the system works end-to-end.

### File: `demo/explore-summarize.workflow.yaml`

```yaml
name: explore-summarize
description: Explore a codebase path and summarize findings
version: "1"

input:
  type: object
  required: [path]
  properties:
    path:
      type: string
      description: File or directory path to explore
    question:
      type: string
      description: What to look for (optional)

steps:
  explore:
    agent: demo-explorer
    input:
      path: ${{ input.path }}
      question: ${{ input.question }}

  summarize:
    agent: demo-summarizer
    input:
      findings: ${{ steps.explore.textOutput }}
      question: ${{ input.question }}
```

### File: `demo/agents/demo-explorer.md`

```markdown
---
name: demo-explorer
description: Explore files and gather information
tools: [read, bash, ls, find, grep]
---
You are a code explorer. Read the files at the given path and gather information.
If a question is provided, focus your exploration on answering it.
Be thorough but concise. Report what you find.
```

### File: `demo/agents/demo-summarizer.md`

```markdown
---
name: demo-summarizer
description: Summarize exploration findings
tools: [read]
---
You are a summarizer. Given exploration findings, produce a clear, structured summary.
If a question was asked, make sure your summary answers it directly.
Keep the summary under 500 words.
```

### Running the demo

```bash
# Install the extension locally
pi install ./pi-workflows

# Copy demo agents to project
cp -r pi-workflows/demo/agents/*.md .pi/agents/
cp -r pi-workflows/demo/*.workflow.yaml .pi/workflows/

# Run the demo
# Option 1: via command
/workflow run explore-summarize --input '{"path": "src/", "question": "What is the main entry point?"}'

# Option 2: via conversation (LLM invokes the tool)
"Explore the src/ directory and summarize what you find about the entry point"
# → LLM calls workflow({ workflow: "explore-summarize", input: { path: "src/", question: "..." } })

# Option 3: headless
pi --mode json -p "Use the workflow tool to run explore-summarize with path src/"
```

### What the demo proves

1. Workflow discovery works (`.pi/workflows/` scanned, spec parsed)
2. Input validation works (path is required)
3. Sequential execution works (explore runs, then summarize)
4. Expression resolution works (`${{ steps.explore.textOutput }}` passes explore's output to summarize)
5. Agent spec loading works (frontmatter parsed, tools restricted)
6. Subprocess dispatch works (two pi processes spawned and completed)
7. TUI widget works (progress shown during execution, if interactive)
8. Result injection works (sendMessage called with formatted result)
9. State persistence works (state.json and session logs written to run directory)

### Acceptance criteria

The demo workflow must:
- [ ] Complete successfully when given a valid path
- [ ] Fail with a clear validation error when path is missing
- [ ] Show a progress widget during execution (interactive mode)
- [ ] Write state.json to the run directory with status "completed"
- [ ] Write session logs for both steps
- [ ] Inject the result into the conversation (sendMessage called)
- [ ] Return structured output accessible to the main agent
- [ ] Work both as a tool invocation and as a `/workflow run` command

