import { describe, it } from "node:test";
import assert from "node:assert";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

// Skip if pi is not available
let hasPi = false;
try {
  const { execSync } = await import("node:child_process");
  execSync("pi --version", { stdio: "ignore" });
  hasPi = true;
} catch {}

describe("full workflow integration", { skip: !hasPi ? "pi not available" : undefined }, () => {
  it("runs the explore-summarize demo end-to-end", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-integration-"));

    // Create project structure
    const wfDir = path.join(tmpDir, ".pi", "workflows");
    const agentDir = path.join(tmpDir, ".pi", "agents");
    fs.mkdirSync(wfDir, { recursive: true });
    fs.mkdirSync(agentDir, { recursive: true });

    // Write a file to explore
    const srcDir = path.join(tmpDir, "src");
    fs.mkdirSync(srcDir, { recursive: true });
    fs.writeFileSync(path.join(srcDir, "main.ts"), 'console.log("hello");');

    // Write workflow spec
    fs.writeFileSync(path.join(wfDir, "explore-summarize.workflow.yaml"), `
name: explore-summarize
description: Explore and summarize
steps:
  explore:
    agent: demo-explorer
    input:
      path: \${{ input.path }}
  summarize:
    agent: demo-summarizer
    input:
      findings: \${{ steps.explore.textOutput }}
`);

    // Write agent specs
    fs.writeFileSync(path.join(agentDir, "demo-explorer.md"), `---
name: demo-explorer
tools: [read, ls]
---
List and read files at the given path. Report what you find.
`);

    fs.writeFileSync(path.join(agentDir, "demo-summarizer.md"), `---
name: demo-summarizer
tools: [read]
---
Summarize the findings. Be brief.
`);

    // Run workflow via pi CLI
    const { execSync } = await import("node:child_process");
    const result = execSync(
      `pi --mode json --extension ./index.ts -p 'Use the workflow tool to run explore-summarize with path "src/"'`,
      { cwd: tmpDir, timeout: 120000, encoding: "utf-8", stdio: ["ignore", "pipe", "pipe"] },
    );

    // Verify run directory was created
    const runDirs = fs.readdirSync(path.join(tmpDir, ".pi", "workflow-runs"));
    assert.ok(runDirs.length >= 1);

    const runDir = path.join(tmpDir, ".pi", "workflow-runs", runDirs[0]);
    assert.ok(fs.existsSync(path.join(runDir, "state.json")));

    const state = JSON.parse(fs.readFileSync(path.join(runDir, "state.json"), "utf-8"));
    assert.strictEqual(state.status, "completed");

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 180000 });
});
```
